from __future__ import annotations

import argparse
import sys
from pathlib import Path

import yaml


# ── Config file resolution ───────────────────────────────────────────────────

DEFAULT_CONFIG = Path("~/.config/wayland-desktop/config.yaml").expanduser()


def _load_yaml(config_arg: str | None) -> tuple[dict, Path]:
    """
    Load the YAML config file.  Returns (data_dict, resolved_path).
    Raises SystemExit with a message if the file cannot be found or parsed.
    """
    if config_arg:
        p = Path(config_arg).expanduser()
        if not p.exists():
            print(f"ERROR: config file not found: {config_arg}", file=sys.stderr)
            sys.exit(1)
    else:
        p = DEFAULT_CONFIG
        if not p.exists():
            # Return empty dict — no config is a valid (default) state
            return {}, p

    try:
        with open(p, encoding="utf-8") as fh:
            data = yaml.safe_load(fh) or {}
        return data, p
    except Exception as exc:
        print(f"ERROR: cannot parse config file {p}: {exc}", file=sys.stderr)
        sys.exit(1)


# ── Value formatting ─────────────────────────────────────────────────────────

def _format_value(value, *, compact: bool = False) -> str:
    """
    Format a config value for terminal display.

    Booleans → "true" / "false"
    None     → "(not set)"
    str/int  → str(value)
    list     → "[ item1, item2, ... ]" (compact) or "[N items]" (summarised)
    dict     → rendered as indented key: value lines
    """
    if value is None:
        return "(not set)"
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, (int, float)):
        return str(value)
    if isinstance(value, str):
        return value
    if isinstance(value, list):
        if compact or len(value) <= 4:
            items = ", ".join(str(v) for v in value)
            return f"[ {items} ]"
        return f"[{len(value)} items]"
    if isinstance(value, dict):
        lines = []
        for k, v in value.items():
            lines.append(f"  {k}: {_format_value(v, compact=True)}")
        return "\n" + "\n".join(lines)
    return repr(value)


# ── Commands ─────────────────────────────────────────────────────────────────

def cmd_list(args) -> int:
    """Print all top-level config keys and their values."""
    data, path = _load_yaml(args.config)

    print(f"Config: {path}\n")

    if not data:
        print("  (empty or no config file found — using built-in defaults)")
        return 0

    # Column width for key alignment
    max_key = max((len(k) for k in data), default=0)
    width   = max(max_key, 20)

    for key, value in data.items():
        formatted = _format_value(value)
        if formatted.startswith("\n"):
            # Multi-line dict — print key on its own line then indent
            print(f"{key}:")
            print(formatted)
        else:
            print(f"  {key:<{width}}  {formatted}")

    return 0


def cmd_lookup(args) -> int:
    """
    Navigate to a dot-separated key path and print the value.
    Prints with no trailing newline so shell $() capture works cleanly.
    """
    data, _ = _load_yaml(args.config)
    key_path = args.key

    parts  = key_path.split(".")
    cursor = data

    for i, part in enumerate(parts):
        if not isinstance(cursor, dict):
            traversed = ".".join(parts[:i])
            print(
                f"ERROR: '{traversed}' is not a dict "
                f"(cannot descend into {type(cursor).__name__})",
                file=sys.stderr,
            )
            return 1
        if part not in cursor:
            print(
                f"ERROR: key '{part}' not found"
                + (f" under '{'.'.join(parts[:i])}'" if i else "")
                + f"\nAvailable keys: {', '.join(sorted(cursor.keys())) or '(none)'}",
                file=sys.stderr,
            )
            return 1
        cursor = cursor[part]

    # Print the resolved value — no trailing newline for clean shell capture
    print(_format_value(cursor, compact=True), end="")
    return 0


# ── Main ─────────────────────────────────────────────────────────────────────

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="kwin_getconfig.py",
        description="Inspect ~/.config/wayland-desktop/config.yaml.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=(
            "Examples:\n"
            "  kwin_getconfig.py list\n"
            "  kwin_getconfig.py lookup progress_window\n"
            "  kwin_getconfig.py lookup apps.brave.single_instance\n"
            "  kwin_getconfig.py lookup maximize.height_tolerance\n"
            "  FOLDER=$(kwin_getconfig.py lookup user_scripts_folder)\n"
        ),
    )
    parser.add_argument(
        "--config", default=None, metavar="FILE",
        help="Alternate config file (default: ~/.config/wayland-desktop/config.yaml)",
    )

    sub = parser.add_subparsers(dest="command")
    sub.add_parser("list", help="Print all config keys and values")

    p_lookup = sub.add_parser("lookup", help="Look up a value by dot-path key")
    p_lookup.add_argument(
        "key",
        help=(
            "Dot-separated path to the config value, e.g. "
            "'progress_window', 'apps.brave.single_instance', "
            "'maximize.height_tolerance'"
        ),
    )

    args = parser.parse_args()

    if args.command is None:
        parser.print_help()
        sys.exit(0)

    sys.exit({"list": cmd_list, "lookup": cmd_lookup}[args.command](args))


if __name__ == "__main__":
    main()
